-- ============================================================
-- BASE64 DECODE
-- ============================================================
local b64chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
local function base64Decode(data)
    data = data:gsub('[^'..b64chars..'=]','')
    return (data:gsub('.', function(x)
        if x == '=' then return '' end
        local r,f = '',(b64chars:find(x)-1)
        for i=6,1,-1 do r=r..(f%2^i-f%2^(i-1)>0 and '1' or '0') end
        return r
    end):gsub('%d%d%d%d%d%d%d%d', function(x)
        return string.char(tonumber(x,2))
    end))
end

-- ============================================================
-- IMAGE LOADER
-- ============================================================
local loadedImages = {}
local function loadImage(id, b64data)
    if loadedImages[id] then return loadedImages[id] end
    local fileName = "gui_img_"..id..".png"
    writefile(fileName, base64Decode(b64data))
    local asset = getcustomasset(fileName)
    loadedImages[id] = asset
    return asset
end

