-- MENU CONTENT - DESYNC TOGGLE
-- ============================================================
local desyncOn = false
local DesyncBtn = Instance.new("ImageButton")
DesyncBtn.Size = UDim2.new(0, 310, 0, 55)
DesyncBtn.Position = UDim2.new(0, 0, 0, 10)
DesyncBtn.BackgroundTransparency = 1
DesyncBtn.Image = loadImage("desyncOff", b64_desyncOff)
DesyncBtn.ScaleType = Enum.ScaleType.Stretch
DesyncBtn.Parent = MenuContent

DesyncBtn.MouseButton1Click:Connect(function()
    desyncOn = not desyncOn
    if desyncOn then
        DesyncBtn.Image = loadImage("desyncOn", b64_desyncOn)
        local hrp = Character:FindFirstChild("HumanoidRootPart")
        if hrp then hrp.CFrame = hrp.CFrame * CFrame.new(0, 9999, 0) end
    else
        DesyncBtn.Image = loadImage("desyncOff", b64_desyncOff)
        local hrp = Character:FindFirstChild("HumanoidRootPart")
        if hrp then hrp.CFrame = hrp.CFrame * CFrame.new(0, -9999, 0) end
    end
end)

-- MENU CONTENT - DISABLE ANIMS TOGGLE
local animsOff = false
local savedTracks = {}

local AnimBtn = Instance.new("ImageButton")
AnimBtn.Size = UDim2.new(0, 360, 0, 65)
AnimBtn.Position = UDim2.new(0, 0, 0, 80)
AnimBtn.BackgroundTransparency = 1
AnimBtn.Image = loadImage("animOff", b64_animOff)
AnimBtn.ScaleType = Enum.ScaleType.Stretch
AnimBtn.Parent = MenuContent

AnimBtn.MouseButton1Click:Connect(function()
    animsOff = not animsOff
    local Animator = Humanoid:FindFirstChildOfClass("Animator")
    if animsOff then
        AnimBtn.Image = loadImage("animOn", b64_animOn)
        if Animator then
            for _, t in ipairs(Animator:GetPlayingAnimationTracks()) do
                table.insert(savedTracks, {track=t, speed=t.Speed})
                t:AdjustSpeed(0)
            end
        end
    else
        AnimBtn.Image = loadImage("animOff", b64_animOff)
        for _, s in ipairs(savedTracks) do
            pcall(function() s.track:AdjustSpeed(s.speed) end)
        end
        savedTracks = {}
    end
end)

