-- ============================================================
-- TAB SWITCHING
-- ============================================================
local function switchTab(tab)
    if tab == "main" then
        MainContent.Visible = true
        MenuContent.Visible = false
        MainTabBtn.ImageTransparency = 0
        MenuTabBtn.ImageTransparency = 0.35
    else
        MainContent.Visible = false
        MenuContent.Visible = true
        MainTabBtn.ImageTransparency = 0.35
        MenuTabBtn.ImageTransparency = 0
    end
end

MainTabBtn.MouseButton1Click:Connect(function() switchTab("main") end)
MenuTabBtn.MouseButton1Click:Connect(function() switchTab("menu") end)
switchTab("main")

